}

{
  "chain": [
    {"step": 1, "name": "Extract Facts", "prompt": "Extract product, issue, urgency from this email..."},
    {"step": 2, "name": "Find Solutions", "prompt": "Suggest solutions for this product issue..."},
    {"step": 3, "name": "Draft Response", "prompt": "Write a friendly response using these solutions..."}
  ]
}

{
  "workflow": "Lead-to-Student Pipeline",
  "stages": {
    "capture": {"node": "Webhook", "receives": ["name", "email", "interest", "budget"]},
    "qualify": {"node": "Claude HTTP Request", "classifies": ["serious", "casual", "spam"]},
    "route": {"node": "Switch", "serious": ["personalized email", "CRM", "Slack notify"], "casual": ["template email", "newsletter"]},
    "record": {"node": "Google Sheets", "logs": ["name", "email", "classification", "timestamp"]}
  }
}
